        if 'pc_id' in items:
            q = q.where(TBagPas.pc_id == items['pc_id'])
        if 'pc_id_start' in items:
            q = q.where(TBagPas.pc_id >= items['pc_id_start'])
        if 'pc_id_end' in items:
            q = q.where(TBagPas.pc_id <= items['pc_id_end'])
        
        if 'stat' in items:
            q = q.where(TBagPas.stat == items['stat'])
        if 'stat_start' in items:
            q = q.where(TBagPas.stat >= items['stat_start'])
        if 'stat_end' in items:
            q = q.where(TBagPas.stat <= items['stat_end'])
        
        if 'register_time' in items:
            q = q.where(TBagPas.register_time == items['register_time'])
        if 'register_time_start' in items:
            q = q.where(TBagPas.register_time >= items['register_time_start'])
        if 'register_time_end' in items:
            q = q.where(TBagPas.register_time <= items['register_time_end'])
        
        if 'startime' in items:
            q = q.where(TBagPas.startime == items['startime'])
        if 'startime_start' in items:
            q = q.where(TBagPas.startime >= items['startime_start'])
        if 'startime_end' in items:
            q = q.where(TBagPas.startime <= items['startime_end'])
        
        if 'user_id' in items:
            q = q.where(TBagPas.user_id == items['user_id'])
        if 'user_id_start' in items:
            q = q.where(TBagPas.user_id >= items['user_id_start'])
        if 'user_id_end' in items:
            q = q.where(TBagPas.user_id <= items['user_id_end'])
        
        if 'endtime' in items:
            q = q.where(TBagPas.endtime == items['endtime'])
        if 'endtime_start' in items:
            q = q.where(TBagPas.endtime >= items['endtime_start'])
        if 'endtime_end' in items:
            q = q.where(TBagPas.endtime <= items['endtime_end'])
        
        if 'cate_id' in items:
            q = q.where(TBagPas.cate_id == items['cate_id'])
        if 'cate_id_start' in items:
            q = q.where(TBagPas.cate_id >= items['cate_id_start'])
        if 'cate_id_end' in items:
            q = q.where(TBagPas.cate_id <= items['cate_id_end'])
        

        if 'id' in set_items:
            q = q.where(TBagPas.id.in_(set_items['id']))
        
        if 'pass_num' in set_items:
            q = q.where(TBagPas.pass_num.in_(set_items['pass_num']))
        
        if 'pc_name' in set_items:
            q = q.where(TBagPas.pc_name.in_(set_items['pc_name']))
        
        if 'pc_num' in set_items:
            q = q.where(TBagPas.pc_num.in_(set_items['pc_num']))
        
        if 'pc_id' in set_items:
            q = q.where(TBagPas.pc_id.in_(set_items['pc_id']))
        
        if 'stat' in set_items:
            q = q.where(TBagPas.stat.in_(set_items['stat']))
        
        if 'register_time' in set_items:
            q = q.where(TBagPas.register_time.in_(set_items['register_time']))
        
        if 'startime' in set_items:
            q = q.where(TBagPas.startime.in_(set_items['startime']))
        
        if 'user_id' in set_items:
            q = q.where(TBagPas.user_id.in_(set_items['user_id']))
        
        if 'endtime' in set_items:
            q = q.where(TBagPas.endtime.in_(set_items['endtime']))
        
        if 'cate_id' in set_items:
            q = q.where(TBagPas.cate_id.in_(set_items['cate_id']))
        

        if 'pass_num' in search_items:
            q = q.where(TBagPas.pass_num.like(search_items['pass_num']))
        
        if 'pc_name' in search_items:
            q = q.where(TBagPas.pc_name.like(search_items['pc_name']))
        
    

        orders = []
        for col, val in order_items.items():
            if val == 'asc':          
                #orders.append(TBagPas.cate_id.asc())
                orders.append(TBagPas.id.asc())
            elif val == 'desc':
                #orders.append(TBagPas.cate_id.desc())
                orders.append(TBagPas.id.desc())
            else:
                raise HTTPException(400, 'order value must be asc or desc')
        if len(order_items) > 0:
            q = q.order_by(*orders)
        
        t_bag_pas_list = q.offset(page*page_size-page_size).limit(page_size).all()
        return [SBagPas.parse_obj(t.__dict__) for t in t_bag_pas_list]


