def insert_balance(item: CreateBalance, db: Optional[SessionLocal] = None) -> SBalance:
    data = model2dict(item)
    t = TBalance(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SBalance.parse_obj(t.__dict__)

    
