        for col, val in order_items.items():
            if val == 'asc':          
                #orders.append(TBalanceGive.give_txt.asc())
                orders.append(TBalanceGive.id.asc())
            elif val == 'desc':
                #orders.append(TBalanceGive.give_txt.desc())
                orders.append(TBalanceGive.id.desc())
            else:
                raise HTTPException(400, 'order value must be asc or desc')
        if len(order_items) > 0:
            q = q.order_by(*orders)
        
        t_balance_give_list = q.offset(page*page_size-page_size).limit(page_size).all()
        return [SBalanceGive.parse_obj(t.__dict__) for t in t_balance_give_list]


