def insert_bigorder_initbag(item: CreateBigorderInitbag, db: Optional[SessionLocal] = None) -> SBigorderInitbag:
    data = model2dict(item)
    t = TBigorderInitbag(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SBigorderInitbag.parse_obj(t.__dict__)

    
def delete_bigorder_initbag(bigorder_initbag_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TBigorderInitbag).where(TBigorderInitbag.id == bigorder_initbag_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TBigorderInitbag).where(TBigorderInitbag.id == bigorder_initbag_id).delete()
        db.commit()

    
def update_bigorder_initbag(item: SBigorderInitbag, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TBigorderInitbag).where(TBigorderInitbag.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TBigorderInitbag).where(TBigorderInitbag.id == item.id).update(data)
        db.commit()

    
def get_bigorder_initbag(bigorder_initbag_id: int) -> Optional[SBigorderInitbag]:
    with Dao() as db:
        t = db.query(TBigorderInitbag).where(TBigorderInitbag.id == bigorder_initbag_id).first()
        if t:
            return SBigorderInitbag.parse_obj(t.__dict__)
        else:
            return None


