        orders = []
        for col, val in order_items.items():
            if val == 'asc':          
                #orders.append(TBusinessContent.subject_ubo_id_owner.asc())
                orders.append(TBusinessContent.id.asc())
            elif val == 'desc':
                #orders.append(TBusinessContent.subject_ubo_id_owner.desc())
                orders.append(TBusinessContent.id.desc())
            else:
                raise HTTPException(400, 'order value must be asc or desc')
        if len(order_items) > 0:
            q = q.order_by(*orders)
        
        t_business_content_list = q.offset(page*page_size-page_size).limit(page_size).all()
        return [SBusinessContent.parse_obj(t.__dict__) for t in t_business_content_list]


