def insert_business_license(item: CreateBusinessLicense, db: Optional[SessionLocal] = None) -> SBusinessLicense:
    data = model2dict(item)
    t = TBusinessLicense(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SBusinessLicense.parse_obj(t.__dict__)

    
def delete_business_license(business_license_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TBusinessLicense).where(TBusinessLicense.id == business_license_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TBusinessLicense).where(TBusinessLicense.id == business_license_id).delete()
        db.commit()

    
def update_business_license(item: SBusinessLicense, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TBusinessLicense).where(TBusinessLicense.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TBusinessLicense).where(TBusinessLicense.id == item.id).update(data)
        db.commit()

    
def get_business_license(business_license_id: int) -> Optional[SBusinessLicense]:
    with Dao() as db:
        t = db.query(TBusinessLicense).where(TBusinessLicense.id == business_license_id).first()
        if t:
            return SBusinessLicense.parse_obj(t.__dict__)
        else:
            return None


