        if 'status_start' in items:
            q = q.where(TNotice.status >= items['status_start'])
        if 'status_end' in items:
            q = q.where(TNotice.status <= items['status_end'])
        

        if 'id' in set_items:
            q = q.where(TNotice.id.in_(set_items['id']))
        
        if 'user_ids' in set_items:
            q = q.where(TNotice.user_ids.in_(set_items['user_ids']))
        
        if 'type' in set_items:
            q = q.where(TNotice.type.in_(set_items['type']))
        
        if 'title' in set_items:
            q = q.where(TNotice.title.in_(set_items['title']))
        
        if 'description' in set_items:
            q = q.where(TNotice.description.in_(set_items['description']))
        
        if 'register_time' in set_items:
            q = q.where(TNotice.register_time.in_(set_items['register_time']))
        
        if 'status' in set_items:
            q = q.where(TNotice.status.in_(set_items['status']))
        

        if 'user_ids' in search_items:
            q = q.where(TNotice.user_ids.like(search_items['user_ids']))
        
        if 'type' in search_items:
            q = q.where(TNotice.type.like(search_items['type']))
        
        if 'title' in search_items:
            q = q.where(TNotice.title.like(search_items['title']))
        
        if 'description' in search_items:
            q = q.where(TNotice.description.like(search_items['description']))
        
    

        orders = []
        for col, val in order_items.items():
            if val == 'asc':          
                #orders.append(TNotice.status.asc())
                orders.append(TNotice.id.asc())
            elif val == 'desc':
                #orders.append(TNotice.status.desc())
                orders.append(TNotice.id.desc())
            else:
                raise HTTPException(400, 'order value must be asc or desc')
        if len(order_items) > 0:
            q = q.order_by(*orders)
        
        t_notice_list = q.offset(page*page_size-page_size).limit(page_size).all()
        return [SNotice.parse_obj(t.__dict__) for t in t_notice_list]


