def insert_roomgold(item: CreateRoomgold, db: Optional[SessionLocal] = None) -> SRoomgold:
    data = model2dict(item)
    t = TRoomgold(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SRoomgold.parse_obj(t.__dict__)

    
def delete_roomgold(roomgold_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TRoomgold).where(TRoomgold.id == roomgold_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TRoomgold).where(TRoomgold.id == roomgold_id).delete()
        db.commit()

    
def update_roomgold(item: SRoomgold, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TRoomgold).where(TRoomgold.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TRoomgold).where(TRoomgold.id == item.id).update(data)
        db.commit()

    
def get_roomgold(roomgold_id: int) -> Optional[SRoomgold]:
    with Dao() as db:
        t = db.query(TRoomgold).where(TRoomgold.id == roomgold_id).first()
        if t:
            return SRoomgold.parse_obj(t.__dict__)
        else:
            return None


