def insert_sd_guest(item: CreateSdGuest, db: Optional[SessionLocal] = None) -> SSdGuest:
    data = model2dict(item)
    t = TSdGuest(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SSdGuest.parse_obj(t.__dict__)

    
def delete_sd_guest(sd_guest_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TSdGuest).where(TSdGuest.id == sd_guest_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TSdGuest).where(TSdGuest.id == sd_guest_id).delete()
        db.commit()

    
def update_sd_guest(item: SSdGuest, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TSdGuest).where(TSdGuest.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TSdGuest).where(TSdGuest.id == item.id).update(data)
        db.commit()

    
def get_sd_guest(sd_guest_id: int) -> Optional[SSdGuest]:
    with Dao() as db:
        t = db.query(TSdGuest).where(TSdGuest.id == sd_guest_id).first()
        if t:
            return SSdGuest.parse_obj(t.__dict__)
        else:
            return None


