def insert_sd_topic(item: CreateSdTopic, db: Optional[SessionLocal] = None) -> SSdTopic:
    data = model2dict(item)
    t = TSdTopic(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SSdTopic.parse_obj(t.__dict__)

    
def delete_sd_topic(sd_topic_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TSdTopic).where(TSdTopic.id == sd_topic_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TSdTopic).where(TSdTopic.id == sd_topic_id).delete()
        db.commit()

    
def update_sd_topic(item: SSdTopic, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TSdTopic).where(TSdTopic.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TSdTopic).where(TSdTopic.id == item.id).update(data)
        db.commit()

    
def get_sd_topic(sd_topic_id: int) -> Optional[SSdTopic]:
    with Dao() as db:
        t = db.query(TSdTopic).where(TSdTopic.id == sd_topic_id).first()
        if t:
            return SSdTopic.parse_obj(t.__dict__)
        else:
            return None


