def insert_sh_consumption(item: CreateShConsumption, db: Optional[SessionLocal] = None) -> SShConsumption:
    data = model2dict(item)
    t = TShConsumption(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SShConsumption.parse_obj(t.__dict__)

    
def delete_sh_consumption(sh_consumption_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TShConsumption).where(TShConsumption.id == sh_consumption_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TShConsumption).where(TShConsumption.id == sh_consumption_id).delete()
        db.commit()

    
def update_sh_consumption(item: SShConsumption, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TShConsumption).where(TShConsumption.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TShConsumption).where(TShConsumption.id == item.id).update(data)
        db.commit()

    
def get_sh_consumption(sh_consumption_id: int) -> Optional[SShConsumption]:
    with Dao() as db:
        t = db.query(TShConsumption).where(TShConsumption.id == sh_consumption_id).first()
        if t:
            return SShConsumption.parse_obj(t.__dict__)
        else:
            return None


