def insert_sh_shop(item: CreateShShop, db: Optional[SessionLocal] = None) -> SShShop:
    data = model2dict(item)
    t = TShShop(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SShShop.parse_obj(t.__dict__)

    
def delete_sh_shop(sh_shop_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TShShop).where(TShShop.id == sh_shop_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TShShop).where(TShShop.id == sh_shop_id).delete()
        db.commit()

    
def update_sh_shop(item: SShShop, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TShShop).where(TShShop.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TShShop).where(TShShop.id == item.id).update(data)
        db.commit()

    
def get_sh_shop(sh_shop_id: int) -> Optional[SShShop]:
    with Dao() as db:
        t = db.query(TShShop).where(TShShop.id == sh_shop_id).first()
        if t:
            return SShShop.parse_obj(t.__dict__)
        else:
            return None


