        if 'store_id_start' in items:
            q = q.where(TStoreTag.store_id >= items['store_id_start'])
        if 'store_id_end' in items:
            q = q.where(TStoreTag.store_id <= items['store_id_end'])
        
        if 'tag_id' in items:
            q = q.where(TStoreTag.tag_id == items['tag_id'])
        if 'tag_id_start' in items:
            q = q.where(TStoreTag.tag_id >= items['tag_id_start'])
        if 'tag_id_end' in items:
            q = q.where(TStoreTag.tag_id <= items['tag_id_end'])
        
        if 'register_time' in items:
            q = q.where(TStoreTag.register_time == items['register_time'])
        if 'register_time_start' in items:
            q = q.where(TStoreTag.register_time >= items['register_time_start'])
        if 'register_time_end' in items:
            q = q.where(TStoreTag.register_time <= items['register_time_end'])
        
        if 'operator_id' in items:
            q = q.where(TStoreTag.operator_id == items['operator_id'])
        if 'operator_id_start' in items:
            q = q.where(TStoreTag.operator_id >= items['operator_id_start'])
        if 'operator_id_end' in items:
            q = q.where(TStoreTag.operator_id <= items['operator_id_end'])
        

        if 'id' in set_items:
            q = q.where(TStoreTag.id.in_(set_items['id']))
        
        if 'store_id' in set_items:
            q = q.where(TStoreTag.store_id.in_(set_items['store_id']))
        
        if 'tag_id' in set_items:
            q = q.where(TStoreTag.tag_id.in_(set_items['tag_id']))
        
