def insert_taskclockup(item: CreateTaskclockup, db: Optional[SessionLocal] = None) -> STaskclockup:
    data = model2dict(item)
    t = TTaskclockup(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return STaskclockup.parse_obj(t.__dict__)

    
