    if db:
        db.query(TTaskclockup).where(TTaskclockup.id == taskclockup_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TTaskclockup).where(TTaskclockup.id == taskclockup_id).delete()
        db.commit()

    
