def insert_tran_account(item: CreateTranAccount, db: Optional[SessionLocal] = None) -> STranAccount:
    data = model2dict(item)
    t = TTranAccount(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return STranAccount.parse_obj(t.__dict__)

    
def delete_tran_account(tran_account_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TTranAccount).where(TTranAccount.id == tran_account_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TTranAccount).where(TTranAccount.id == tran_account_id).delete()
        db.commit()

    
def update_tran_account(item: STranAccount, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TTranAccount).where(TTranAccount.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TTranAccount).where(TTranAccount.id == item.id).update(data)
        db.commit()

    
def get_tran_account(tran_account_id: int) -> Optional[STranAccount]:
    with Dao() as db:
        t = db.query(TTranAccount).where(TTranAccount.id == tran_account_id).first()
        if t:
            return STranAccount.parse_obj(t.__dict__)
        else:
            return None


