def insert_user_adbrand(item: CreateUserAdbrand, db: Optional[SessionLocal] = None) -> SUserAdbrand:
    data = model2dict(item)
    t = TUserAdbrand(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SUserAdbrand.parse_obj(t.__dict__)

    
def delete_user_adbrand(user_adbrand_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TUserAdbrand).where(TUserAdbrand.id == user_adbrand_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TUserAdbrand).where(TUserAdbrand.id == user_adbrand_id).delete()
        db.commit()

    
def update_user_adbrand(item: SUserAdbrand, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TUserAdbrand).where(TUserAdbrand.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TUserAdbrand).where(TUserAdbrand.id == item.id).update(data)
        db.commit()

    
def get_user_adbrand(user_adbrand_id: int) -> Optional[SUserAdbrand]:
    with Dao() as db:
        t = db.query(TUserAdbrand).where(TUserAdbrand.id == user_adbrand_id).first()
        if t:
            return SUserAdbrand.parse_obj(t.__dict__)
        else:
            return None


