def insert_video_recharge_log(item: CreateVideoRechargeLog, db: Optional[SessionLocal] = None) -> SVideoRechargeLog:
    data = model2dict(item)
    t = TVideoRechargeLog(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SVideoRechargeLog.parse_obj(t.__dict__)

    
def delete_video_recharge_log(video_recharge_log_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TVideoRechargeLog).where(TVideoRechargeLog.id == video_recharge_log_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoRechargeLog).where(TVideoRechargeLog.id == video_recharge_log_id).delete()
        db.commit()

    
def update_video_recharge_log(item: SVideoRechargeLog, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TVideoRechargeLog).where(TVideoRechargeLog.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoRechargeLog).where(TVideoRechargeLog.id == item.id).update(data)
        db.commit()

    
def get_video_recharge_log(video_recharge_log_id: int) -> Optional[SVideoRechargeLog]:
    with Dao() as db:
        t = db.query(TVideoRechargeLog).where(TVideoRechargeLog.id == video_recharge_log_id).first()
        if t:
            return SVideoRechargeLog.parse_obj(t.__dict__)
        else:
            return None


