def insert_video_task(item: CreateVideoTask, db: Optional[SessionLocal] = None) -> SVideoTask:
    data = model2dict(item)
    t = TVideoTask(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SVideoTask.parse_obj(t.__dict__)

    
def delete_video_task(video_task_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TVideoTask).where(TVideoTask.id == video_task_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoTask).where(TVideoTask.id == video_task_id).delete()
        db.commit()

    
def update_video_task(item: SVideoTask, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TVideoTask).where(TVideoTask.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoTask).where(TVideoTask.id == item.id).update(data)
        db.commit()

    
def get_video_task(video_task_id: int) -> Optional[SVideoTask]:
    with Dao() as db:
        t = db.query(TVideoTask).where(TVideoTask.id == video_task_id).first()
        if t:
            return SVideoTask.parse_obj(t.__dict__)
        else:
            return None


