def insert_video_task_material(item: CreateVideoTaskMaterial, db: Optional[SessionLocal] = None) -> SVideoTaskMaterial:
    data = model2dict(item)
    t = TVideoTaskMaterial(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SVideoTaskMaterial.parse_obj(t.__dict__)

    
def delete_video_task_material(video_task_material_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TVideoTaskMaterial).where(TVideoTaskMaterial.id == video_task_material_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoTaskMaterial).where(TVideoTaskMaterial.id == video_task_material_id).delete()
        db.commit()

    
def update_video_task_material(item: SVideoTaskMaterial, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TVideoTaskMaterial).where(TVideoTaskMaterial.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoTaskMaterial).where(TVideoTaskMaterial.id == item.id).update(data)
        db.commit()

    
def get_video_task_material(video_task_material_id: int) -> Optional[SVideoTaskMaterial]:
    with Dao() as db:
        t = db.query(TVideoTaskMaterial).where(TVideoTaskMaterial.id == video_task_material_id).first()
        if t:
            return SVideoTaskMaterial.parse_obj(t.__dict__)
        else:
            return None


