def insert_video_task_type(item: CreateVideoTaskType, db: Optional[SessionLocal] = None) -> SVideoTaskType:
    data = model2dict(item)
    t = TVideoTaskType(**data)
    if db:
        db.add(t)
        db.flush()
        db.refresh(t)
        return SAddress.parse_obj(t.__dict__)
    with Dao() as db:
        db.add(t)
        db.commit()
        db.refresh(t)
    return SVideoTaskType.parse_obj(t.__dict__)

    
def delete_video_task_type(video_task_type_id: int, db: Optional[SessionLocal] = None):
    if db:
        db.query(TVideoTaskType).where(TVideoTaskType.id == video_task_type_id).delete()
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoTaskType).where(TVideoTaskType.id == video_task_type_id).delete()
        db.commit()

    
def update_video_task_type(item: SVideoTaskType, db: Optional[SessionLocal] = None):
    data = model2dict(item)
    data.pop('id')
    if db:
        db.query(TVideoTaskType).where(TVideoTaskType.id == item.id).update(data)
        db.flush()
        return
    
    with Dao() as db:
        db.query(TVideoTaskType).where(TVideoTaskType.id == item.id).update(data)
        db.commit()

    
def get_video_task_type(video_task_type_id: int) -> Optional[SVideoTaskType]:
    with Dao() as db:
        t = db.query(TVideoTaskType).where(TVideoTaskType.id == video_task_type_id).first()
        if t:
            return SVideoTaskType.parse_obj(t.__dict__)
        else:
            return None


